class AudioChunkPlayer extends StatefulWidget {
  final double angle;
  final double velocity;
  final double gravity;
  final String? customFormula;
  final String language;

  const AudioChunkPlayer({
    super.key,
    required this.angle,
    required this.velocity,
    required this.gravity,
    this.customFormula,
    this.language = 'te-IN',
  });

  @override
  State<AudioChunkPlayer> createState() => _AudioChunkPlayerState();
}

class _AudioChunkPlayerState extends State<AudioChunkPlayer> {
  final AudioPlayer _audioPlayer = AudioPlayer();
  List<AudioChunk> _chunks = [];
  bool _isLoading = true;
  String? _playingChunkId;
  String _selectedLanguage = 'te-IN';

  @override
  void initState() {
    super.initState();
    _selectedLanguage = widget.language;
    _audioPlayer.onPlayerComplete.listen((_) {
      if (mounted) {
        setState(() {
          _playingChunkId = null;
        });
      }
    });
    _loadChunks();
  }

  @override
  void didUpdateWidget(AudioChunkPlayer oldWidget) {
    super.didUpdateWidget(oldWidget);
    if (oldWidget.angle != widget.angle ||
        oldWidget.velocity != widget.velocity ||
        oldWidget.gravity != widget.gravity) {
      _loadChunks();
    }
  }

  @override
  void dispose() {
    _audioPlayer.dispose();
    super.dispose();
  }

  Future<void> _loadChunks() async {
    setState(() {
      _isLoading = true;
    });

    try {
      final response = await http
          .post(
            Uri.parse('${ApiService.apiBaseUrl}/api/chunks'),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({
              'angle': widget.angle,
              'velocity': widget.velocity,
              'gravity': widget.gravity,
              'custom_formula': widget.customFormula,
              'include_formula': widget.customFormula != null &&
                  widget.customFormula!.isNotEmpty,
              'language': _selectedLanguage,
            }),
          )
          .timeout(const Duration(seconds: 60));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        final List<dynamic> chunkList = data['chunks'] ?? [];

        if (mounted) {
          setState(() {
            _chunks =
                chunkList.map((json) => AudioChunk.fromJson(json)).toList();
            _isLoading = false;
          });
        }
      } else {
        if (mounted) {
          setState(() {
            _isLoading = false;
          });
          _showError('Failed to load explanations');
        }
      }
    } catch (e) {
      debugPrint('Error loading chunks: $e');
      if (mounted) {
        setState(() {
          _isLoading = false;
        });
        _showError('Error loading explanations');
      }
    }
  }

  Future<void> _playChunk(AudioChunk chunk) async {
    if (_playingChunkId == chunk.chunkId) {
      await _audioPlayer.stop();
      setState(() {
        _playingChunkId = null;
      });
      return;
    }

    final audioUrl =
        _selectedLanguage == 'te-IN' ? chunk.audioUrlTe : chunk.audioUrlEn;

    if (audioUrl == null || audioUrl.isEmpty) {
      _showError('Audio not available for this explanation');
      return;
    }

    setState(() {
      _playingChunkId = chunk.chunkId;
    });

    try {
      await _audioPlayer.stop();
      await _audioPlayer.play(UrlSource(audioUrl));
    } catch (e) {
      debugPrint('Error playing audio: $e');
      setState(() {
        _playingChunkId = null;
      });
      _showError('Error playing audio');
    }
  }

  Future<void> _playAllChunks() async {
    if (_chunks.isEmpty) return;

    setState(() {
      _playingChunkId = _chunks.first.chunkId;
    });

    for (int i = 0; i < _chunks.length; i++) {
      if (_playingChunkId == null) break;

      final chunk = _chunks[i];
      final audioUrl =
          _selectedLanguage == 'te-IN' ? chunk.audioUrlTe : chunk.audioUrlEn;

      if (audioUrl != null && audioUrl.isNotEmpty) {
        try {
          await _audioPlayer.stop();
          await _audioPlayer.play(UrlSource(audioUrl));
          await Future.delayed(const Duration(milliseconds: 100));
          while (_audioPlayer.state == PlayerState.playing) {
            await Future.delayed(const Duration(milliseconds: 500));
          }
        } catch (e) {
          debugPrint('Error playing chunk $i: $e');
        }
      }
    }

    if (mounted) {
      setState(() {
        _playingChunkId = null;
      });
    }
  }

  Future<void> _stopAll() async {
    await _audioPlayer.stop();
    setState(() {
      _playingChunkId = null;
    });
  }

  void _showError(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        duration: const Duration(seconds: 2),
      ),
    );
  }

  void _toggleLanguage() {
    setState(() {
      _selectedLanguage = _selectedLanguage == 'te-IN' ? 'en-IN' : 'te-IN';
    });
    _loadChunks();
  }

  IconData _getCategoryIcon(String category) {
    switch (category) {
      case 'concept':
        return Icons.lightbulb_outline;
      case 'formula':
        return Icons.functions;
      case 'results':
        return Icons.analytics_outlined;
      case 'change':
        return Icons.trending_up;
      case 'summary':
        return Icons.summarize_outlined;
      default:
        return Icons.play_circle_outline;
    }
  }

  Color _getCategoryColor(String category) {
    switch (category) {
      case 'concept':
        return Colors.blue;
      case 'formula':
        return Colors.purple;
      case 'results':
        return Colors.green;
      case 'change':
        return Colors.orange;
      case 'summary':
        return Colors.teal;
      default:
        return Colors.grey;
    }
  }

