              ? chunk.audioUrlTe
              : chunk.audioUrlEn)
          .where((url) => url != null && url.isNotEmpty)
          .toList();

      if (audioUrls.isEmpty) {
        _showError('No audio available to combine');
        setState(() {
          _isCombining = false;
        });
        return;
      }

      final response = await http
          .post(
            Uri.parse('${ApiService.apiBaseUrl}/api/combine-chunks'),
            headers: {'Content-Type': 'application/json'},
            body: jsonEncode({
              'audio_urls': audioUrls,
            }),
          )
          .timeout(const Duration(seconds: 120));

      if (response.statusCode == 200) {
        final data = jsonDecode(response.body);
        final combinedUrl = data['combined_audio_url'];

        if (combinedUrl != null) {
          setState(() {
            _playingChunkId = 'combined';
          });

          await _audioPlayer.stop();
          await _audioPlayer.play(UrlSource(combinedUrl));
        } else {
          _showError('Failed to combine audio chunks');
        }
      } else {
        _showError('Failed to combine audio chunks');
      }
    } catch (e) {
      debugPrint('Error combining audio: $e');
      _showError('Error combining audio chunks');
    } finally {
      if (mounted) {
        setState(() {
          _isCombining = false;
        });
      }
    }
  }

  void _showError(String message) {
    if (!mounted) return;
    ScaffoldMessenger.of(context).showSnackBar(
      SnackBar(
        content: Text(message),
        duration: const Duration(seconds: 2),
      ),
    );
  }

  void _toggleLanguage() {
    setState(() {
      _selectedLanguage = _selectedLanguage == 'te-IN' ? 'en-IN' : 'te-IN';
    });
    _loadChunks();
  }

  IconData _getCategoryIcon(String category) {
    switch (category) {
      case 'concept':
        return Icons.lightbulb_outline;
      case 'formula':
        return Icons.functions;
      case 'results':
        return Icons.analytics_outlined;
      case 'change':
        return Icons.trending_up;
      case 'summary':
        return Icons.summarize_outlined;
      default:
        return Icons.play_circle_outline;
    }
  }

  Color _getCategoryColor(String category) {
    switch (category) {
      case 'concept':
        return Colors.blue;
      case 'formula':
        return Colors.purple;
      case 'results':
        return Colors.green;
      case 'change':
        return Colors.orange;
      case 'summary':
        return Colors.teal;
      default:
        return Colors.grey;
    }
  }

  @override
  Widget build(BuildContext context) {
    return Card(
      margin: const EdgeInsets.all(8),
      child: Column(
        crossAxisAlignment: CrossAxisAlignment.stretch,
        children: [
          Padding(
            padding: const EdgeInsets.all(12),
            child: Row(
              children: [
                const Icon(Icons.audiotrack, color: Colors.deepPurple),
                const SizedBox(width: 8),
                Expanded(
                  child: Text(
                    'Telugu-English Lecture',
                    style: Theme.of(context).textTheme.titleMedium,
                  ),
                ),
                TextButton.icon(
                  onPressed: _toggleLanguage,
                  icon: Icon(
                    _selectedLanguage == 'te-IN'
                        ? Icons.language
                        : Icons.translate,
                    size: 18,
                  ),
                  label: Text(
                    _selectedLanguage == 'te-IN' ? 'తెలుగు' : 'English',
                    style: const TextStyle(fontSize: 12),
                  ),
                ),
              ],
            ),
          ),
          const Divider(height: 1),
          if (_isLoading)
            const Padding(
              padding: EdgeInsets.all(32),
              child: Center(
                child: Column(
                  children: [
                    CircularProgressIndicator(),
                    SizedBox(height: 16),
                    Text('Loading explanations...'),
                  ],
                ),
              ),
            )
          else if (_chunks.isEmpty)
            const Padding(
              padding: EdgeInsets.all(32),
              child: Center(child: Text('No explanations available')),
            )
          else
            Column(
              children: [
                Padding(
                  padding: const EdgeInsets.all(8),
                  child: Row(
                    children: [
                      Expanded(
                        child: ElevatedButton.icon(
                          onPressed: _playAllChunks,
                          icon: const Icon(Icons.play_arrow),
                          label: const Text('Play All'),
                          style: ElevatedButton.styleFrom(
                            backgroundColor: Colors.deepPurple,
                            foregroundColor: Colors.white,
                          ),
                        ),
                      ),
                      const SizedBox(width: 8),
                      Expanded(
                        child: ElevatedButton.icon(
                          onPressed: _isCombining ? null : _combineAndPlayAll,
                          icon: _isCombining
                              ? const SizedBox(
                                  width: 16,
                                  height: 16,
                                  child: CircularProgressIndicator(
                                    strokeWidth: 2,
                                    color: Colors.white,
                                  ),
                                )
                              : const Icon(Icons.merge_type),
                          label:
                              Text(_isCombining ? 'Combining...' : 'Combine'),
                          style: ElevatedButton.styleFrom(
                            backgroundColor: Colors.indigo,
                            foregroundColor: Colors.white,
                          ),
                        ),
                      ),
                      const SizedBox(width: 8),
                      IconButton(
                        onPressed: _stopAll,
                        icon: const Icon(Icons.stop),
                        tooltip: 'Stop',
                      ),
                      IconButton(
                        onPressed: _loadChunks,
                        icon: const Icon(Icons.refresh),
                        tooltip: 'Refresh',
                      ),
                    ],
                  ),
                ),
                const Divider(height: 1),
                ListView.separated(
                  shrinkWrap: true,
                  physics: const NeverScrollableScrollPhysics(),
                  itemCount: _chunks.length,
                  separatorBuilder: (_, __) => const Divider(height: 1),
                  itemBuilder: (context, index) {
                    final chunk = _chunks[index];
                    final isPlaying = _playingChunkId == chunk.chunkId;
                    final color = _getCategoryColor(chunk.category);

                    return ListTile(
                      leading: CircleAvatar(
                        backgroundColor: color.withValues(alpha: 0.2),
                        child: Icon(
                          _getCategoryIcon(chunk.category),
                          color: color,
                          size: 20,
                        ),
                      ),
                      title: Text(
                        _selectedLanguage == 'te-IN'
                            ? chunk.titleTe
                            : chunk.title,
                        style: TextStyle(
                          fontWeight:
                              isPlaying ? FontWeight.bold : FontWeight.normal,
                          color: isPlaying ? color : null,
                        ),
                      ),
                      subtitle: Text(
                        _selectedLanguage == 'te-IN'
                            ? chunk.title
                            : chunk.titleTe,
                        style: TextStyle(
                          fontSize: 12,
                          color: Colors.grey[600],
                          fontStyle: FontStyle.italic,
                        ),
                      ),
                      trailing: IconButton(
                        icon: Icon(
                          isPlaying ? Icons.stop_circle : Icons.play_circle,
                          color: isPlaying ? Colors.red : color,
                          size: 32,
                        ),
                        onPressed: () => _playChunk(chunk),
                        tooltip: isPlaying ? 'Stop' : 'Play',
                      ),
                      onTap: () => _playChunk(chunk),
                    );
                  },
                ),
              ],
            ),
        ],
      ),
    );
  }
}
